(function(w){"use strict";const ID="potential-energy";function compute(x){const m=Number(x.mass),g=Number(x.gravity),h=Number(x.height);if(!Number.isFinite(m)||!Number.isFinite(g)||!Number.isFinite(h))return{error:"값을 올바르게 입력해 주세요."};return{value:m*g*h};}
function render(root,api){root.innerHTML=`<div class="hm-calc-panel"><div class="hm-calc-form"><div class="hm-calc-grid-2"><div class="hm-calc-field"><label>질량 (kg)</label><input class="hm-calc-input" inputmode="decimal" data-key="mass" placeholder="" value=""></div><div class="hm-calc-field"><label>중력가속도 (m/s²)</label><input class="hm-calc-input" inputmode="decimal" data-key="gravity" placeholder="" value="9.80665"></div><div class="hm-calc-field"><label>높이 (m)</label><input class="hm-calc-input" inputmode="decimal" data-key="height" placeholder="" value=""></div></div><div class="hm-calc-actions"><button type="button" class="hm-calc-btn">계산하기</button></div><p class="hm-calc-message" hidden></p></div><div class="hm-calc-result" hidden></div></div>`;const inputs=Array.prototype.slice.call(root.querySelectorAll("input[data-key]")),go=root.querySelector("button"),msg=root.querySelector(".hm-calc-message"),res=root.querySelector(".hm-calc-result");go.addEventListener("click",()=>{const x={};inputs.forEach(i=>x[i.dataset.key]=api.parseNumber(i.value));const r=compute(x);if(r.error){api.setMessage(msg,r.error);api.clearResult(res);return}api.setMessage(msg,"");api.setResult(res,api.resultCard("위치에너지",`${api.formatNumber(r.value,8)} J`,"PE = mgh"));});}
w.HM_CALC.register(ID,{compute,render});})(window);
